/**
 * Real Estate Scraper & Scoring System v4.0
 * Ultra Strict Edition - Max 5 Alerts Per Run
 */

// 1. Configuration
const CONFIG = {
    PPM_LIMITS: { 
        STEAL: 25000,      // Absolute steal
        GOOD: 35000,       // Very good
        AVERAGE: 50000,    // Market average
        MIN_VALID: 15000   // Below this = scam
    },
    TOTAL_PRICE_LIMITS: { 
        BUDGET: 3000000,   // Rare find
        MID_RANGE: 5000000 // Affordable
    },
    AREA_LIMITS: { 
        MIN_OPTIMAL: 150,  // Minimum good size
        MAX_OPTIMAL: 200   // Maximum optimal
    },
    SCORE_LIMITS: { 
        EXCELLENT: 13,     // Only the best
        GOOD: 8            // Good deals
    },
    ALERT: {
        MIN_SCORE: 13,     // Minimum score for alert
        MAX_PPM: 25000,    // Maximum PPM for alert
        MAX_PRICE: 3000000,// Maximum price for alert
        MIN_BEDS: 3        // Minimum beds for alert
    },
    DOMAIN: "https://www.dubizzle.com.eg"
};

// 2. Helper Functions
const cleanNumeric = (val) => {
    if (!val) return 0;
    return Number(String(val).replace(/[^\d.]/g, '')) || 0;
};

const getSafeArray = (val) => Array.isArray(val) ? val : [val];

const results = [];

for (const item of $input.all()) {
    const data = item.json;

    const fields = {
        prices:    getSafeArray(data["Total Price"]),
        beds:      getSafeArray(data["beds"]),
        bathrooms: getSafeArray(data["bathrooms"]),
        areas:     getSafeArray(data["area"]),
        titles:    getSafeArray(data["title"]),
        locations: getSafeArray(data["location"]),
        dates:     getSafeArray(data["listing_date"]),
        urls:      getSafeArray(data["listing_url"]),
        verified:  getSafeArray(data["verified"]),
    };

    for (let i = 0; i < fields.prices.length; i++) {
        const rawPrice = String(fields.prices[i] || "");
        if (!rawPrice.includes("EGP")) continue;

        const cleanPrice = cleanNumeric(rawPrice);
        const cleanArea  = cleanNumeric(fields.areas[i]);

        // Data Integrity Check
        if (cleanPrice <= 0 || cleanArea <= 0) continue;

        const ppm     = Math.round(cleanPrice / cleanArea);
        const fullUrl = String(fields.urls[i] || "").startsWith("http")
            ? fields.urls[i]
            : `${CONFIG.DOMAIN}${fields.urls[i]}`;

        // --- Scoring ---
        let score = 0;
        const reasons = [];

        // A. Price Per SQM (Weight: 6)
        if (ppm > CONFIG.PPM_LIMITS.MIN_VALID && ppm < CONFIG.PPM_LIMITS.STEAL) {
            score += 6; reasons.push("Exceptional PPM 🔥");
        } else if (ppm >= CONFIG.PPM_LIMITS.STEAL && ppm < CONFIG.PPM_LIMITS.GOOD) {
            score += 4; reasons.push("Good PPM 💰");
        } else if (ppm >= CONFIG.PPM_LIMITS.GOOD && ppm < CONFIG.PPM_LIMITS.AVERAGE) {
            score += 2;
        }

        // B. Total Price (Weight: 2)
        if (cleanPrice > 0 && cleanPrice < CONFIG.TOTAL_PRICE_LIMITS.BUDGET) {
            score += 2; reasons.push("Budget Friendly 💚");
        } else if (cleanPrice < CONFIG.TOTAL_PRICE_LIMITS.MID_RANGE) {
            score += 1;
        }

        // C. Area (Weight: 2)
        if (cleanArea >= CONFIG.AREA_LIMITS.MIN_OPTIMAL && cleanArea <= CONFIG.AREA_LIMITS.MAX_OPTIMAL) {
            score += 2; reasons.push("Optimal Size 📐");
        } else if (cleanArea > CONFIG.AREA_LIMITS.MAX_OPTIMAL) {
            score += 1;
        }

        // D. Verification (Weight: 2)
        const isVerified = String(fields.verified[i] || "").includes("Yes");
        if (isVerified) {
            score += 2; reasons.push("Verified Seller ✅");
        }

        // E. Bedrooms (Weight: 1)
        const bedsCount = Number(fields.beds[i]) || 0;
        if (bedsCount >= CONFIG.ALERT.MIN_BEDS) {
            score += 1; reasons.push("Family Size 🛏");
        }

        // F. Freshness (Weight: 1)
        const isFresh = String(fields.dates[i] || "").includes("hour");
        if (isFresh) {
            score += 1; reasons.push("New Listing ⚡");
        }

        // G. Bonus - Both Exceptional PPM AND Budget Price
        if (ppm < CONFIG.PPM_LIMITS.STEAL && cleanPrice < CONFIG.TOTAL_PRICE_LIMITS.BUDGET) {
            score += 2; reasons.push("Double Value Bonus 💎");
        }

        // --- Classification ---
        const dealLabel = score >= CONFIG.SCORE_LIMITS.EXCELLENT ? "Excellent Deal 🔥" :
                          score >= CONFIG.SCORE_LIMITS.GOOD ? "Good Deal 🟢" :
                          "Normal 🟡";

        // --- Ultra Strict Alert Conditions ---
        // ALL 5 conditions must be true
        const isActionable = (
            score >= CONFIG.ALERT.MIN_SCORE &&        // Very high score
            ppm < CONFIG.ALERT.MAX_PPM &&             // Absolute steal PPM
            isVerified &&                              // Must be verified
            cleanPrice < CONFIG.ALERT.MAX_PRICE &&    // Must be affordable
            bedsCount >= CONFIG.ALERT.MIN_BEDS        // Must be family size
        );

        results.push({
            json: {
                id:            Buffer.from(fullUrl).toString('base64').substring(0, 12),
                price:         cleanPrice,
                beds:          bedsCount,
                bathrooms:     fields.bathrooms[i] || "",
                area:          cleanArea,
                price_per_sqm: ppm,
                title:         fields.titles[i] || "",
                location:      fields.locations[i] || "N/A",
                listing_date:  fields.dates[i] || "",
                listing_url:   fullUrl,
                verified:      isVerified ? "Yes" : "No",
                deal_score:    score,
                deal_label:    dealLabel,
                deal_reasons:  reasons.join(", "),
                is_actionable: isActionable,
                analyzed_at:   new Date().toISOString(),
            }
        });
    }
}

return results;

const baseURL = "https://www.dubizzle.com.eg/en/properties/apartments-duplex-for-sale/cairo/?page=";
const totalPages = 5; // reduce from 5 to 3
const results = [];

for (let i = 1; i <= totalPages; i++) {
  results.push({ json: { url: baseURL + i } });
}

return results;
